st decimals = Math.max(0, -Math.floor(Math.log10(props.step)));\n  return Number(props.value).toFixed(decimals);\n});\n\nfunction updateValueFromMouse(e: MouseEvent) {\n  if (!trackRef.value) return;\n  const rect = trackRef.value.getBoundingClientRect();\n  let x = e.clientX - rect.left;\n  if (x < 0) x = 0;\n  if (x > rect.width) x = rect.width;\n\n  const p = x / rect.width;\n  let newVal = props.min + p * (props.max - props.min);\n  // 吸附到 step\n  newVal = Math.round(newVal / props.step) * props.step;\n  // 限制范围\n  newVal = Math.max(props.min, Math.min(props.max, newVal));\n  emit('update:value', newVal);\n}\n\nfunction onMouseDown(e: MouseEvent) {\n  isDragging.value = true;\n  updateValueFromMouse(e);\n  document.addEventListener('mousemove', onMouseMove);\n  document.addEventListener('mouseup', onMouseUp);\n}\n\nfunction onMouseMove(e: MouseEvent) {\n  if (!isDragging.value) return;\n  updateValueFromMouse(e);\n}\n\nfunction onMouseUp() {\n  isDragging.value = false;\n  document.removeEventListener('mousemove', onMouseMove);\n  document.removeEventListener('mouseup', onMouseUp);\n}\n\n// Fix #4: 确保组件卸载时清理事件监听器\nonUnmounted(() => {\n  document.removeEventListener('mousemove', onMouseMove);\n  document.removeEventListener('mouseup', onMouseUp);\n});\n</script>\n\n<style scoped>\n.premium-slider {\n  display: flex;\n  flex-direction: column;\n  gap: 8px;\n  width: 100%;\n  padding: 4px 0;\n}\n\n.ps-header {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n}\n\n.ps-label {\n  font-size: 13px;\n  font-weight: 500;\n  color: rgba(255, 255, 255, 0.85);\n}\n\n.ps-value {\n  font-size: 12px;\n  font-family: monospace;\n  color: rgba(100, 181, 246, 0.9);\n  background: rgba(100, 181, 246, 0.1);\n  padding: 2px 6px;\n  border-radius: 4px;\n}\n\n.ps-track-container {\n  position: relative;\n  height: 24px;\n  display: flex;\n  align-items: center;\n  cursor: pointer;\n}\n\n.ps-track-bg {\n  position: absolute;\n  left: 0;\n  right: 0;\n  height: 6px;\n  background: rgba(255, 255, 255, 0.1);\n  border-radius: 3px;\n  box-shadow: inset 0 1px 2px rgba(0, 0, 0, 0.2);\n}\n\n.ps-track-fill {\n  position: absolute;\n  left: 0;\n  height: 6px;\n  background: linear-gradient(90deg, #64b5f6, #2196f3);\n  border-radius: 3px;\n  pointer-events: none;\n  box-shadow: 0 0 8px rgba(33, 150, 243, 0.4);\n}\n\n.ps-thumb {\n  position: absolute;\n  width: 16px;\n  height: 16px;\n  background: #ffffff;\n  border-radius: 50%;\n  transform: translateX(-50%);\n  box-shadow: 0 2px 6px rgba(0, 0, 0, 0.3);\n  pointer-events: none;\n  transition: box-shadow 0.2s, transform 0.1s;\n}\n\n.ps-track-container:active .ps-thumb {\n  box-shadow: 0 0 0 6px rgba(100, 181, 246, 0.2);\n  transform: translateX(-50%) scale(1.1);\n}\n</style>\n"],"sourceRoot":""}]);
